sys_script_client.script:
function onSubmit() {

    // Get the date sold value
    var dateSold = g_form.getValue('date_sold_on');

    // If date is not empty, validate it
    if (dateSold) {

        // Get today's date (without time)
        var today = new Date();
        today.setHours(0, 0, 0, 0);

        // Convert the date sold string to Date object
        var dateSoldObj = new Date(dateSold);
        dateSoldObj.setHours(0, 0, 0, 0);

        // Check if date sold is in the past
        if (dateSoldObj < today) {
            alert('Date Sold cannot be in the past. Please select today\'s date or a future date.');
            return false; // Prevent form submission
        }
    }

    return true; // Allow form submission
}
